	private static int runBackgroundFilterSamplingUntilSampled(LmdbSailStore store, EvaluationStatistics statistics,
			Filter filter) throws InterruptedException {
		long deadlineNanos = System.nanoTime() + TimeUnit.SECONDS.toNanos(5L);
		int sampled = 0;
		while (System.nanoTime() - deadlineNanos < 0L) {
			sampled += store.runBackgroundFilterSamplingCycle(250L);
			EvaluationStatistics.FilterPassEstimate estimate = statistics.estimateFilterPass(filter);
			if (estimate.getSource() == EvaluationStatistics.FilterPassEstimate.Source.SAMPLED) {
				return sampled;
			}
			Thread.yield();
		}
		return sampled;
	}

	private static Filter findRecordedOnFilter(TupleExpr tupleExpr) {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI recordedOn = vf.createIRI("http://example.com/theme/medical/recordedOn");
		List<Filter> filters = new ArrayList<>(1);
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Filter node) {
				if (filters.isEmpty()
						&& node.getArg()instanceof StatementPattern statementPattern
						&& statementPattern.getPredicateVar() != null
						&& recordedOn.equals(statementPattern.getPredicateVar().getValue())
						&& VarNameCollector.process(node.getCondition()).contains("date")) {
					filters.add(node);
				}
				super.meet(node);
			}
		});
		return filters.isEmpty() ? null : filters.getFirst();
	}

	private static Filter recordedOnLocalFilter() {
		SimpleValueFactory vf = SimpleValueFactory.getInstance();
		IRI recordedOn = vf.createIRI("http://example.com/theme/medical/recordedOn");
		ListMemberOperator condition = new ListMemberOperator();
		condition.addArgument(new Var("date"));
		condition.addArgument(new ValueConstant(vf.createLiteral("2024-01-01", XMLSchema.DATE)));
		condition.addArgument(new ValueConstant(vf.createLiteral("2024-02-01", XMLSchema.DATE)));
		return new Filter(new StatementPattern(new Var("enc"), new Var("predicate", recordedOn), new Var("date")),
				condition);
	}

